import { Row, Col, InputGroup, InputGroupAddon, Input, InputGroupText } from "reactstrap";
import DataTable from "react-data-table-component";
import { ChevronDown } from "react-feather";
import React, { Suspense, useEffect, useState, lazy } from "react";

import { Search } from "react-feather";

import { apiPostMethod } from "@helpers/axiosHelper";
import { errorToast } from "@helpers/appHelper";
import Spinner from "reactstrap/lib/Spinner";
import { PrimaryButton } from "../forms/custom-button";
const ExcelDownload = lazy(() => import("../common/ExcelDownload"));

const TableComponent = ({
  hideSearch,
  columns,
  url,
  sheetName,
  fileName,
  showDownload,
  formType,
  postData,
  onDataReceived,
  filterRenderor,
  ...props
}) => {
  const [pageSize, setPageSize] = useState(50);
  const [loading, setLoading] = useState(false);
  const [totalPage, setTotalPage] = useState(0);
  const [currentPage, setCurrentPage] = useState(1);
  const [searchValue, setSearchValue] = useState("");
  const [Tbldata, setTbldata] = useState([]);
  const [downloadExcel, setdowloadExcel] = useState(false);

  useEffect(() => {
    setTbldata(props.data);
  }, [props.data]);

  useEffect(() => {
    if (url) {
      let start = (currentPage - 1) * pageSize;
      let fdata = {
        formType: formType,
        startCount: start,
        pageSize: pageSize,
        ...postData,
      };
      if (searchValue && searchValue.length) {
        fdata = { ...fdata, searchTxt: searchValue };
      }
      setLoading(true);
      apiPostMethod(url, fdata)
        .then((response) => {
          const { data } = response;
          if (data.success) {
            if (onDataReceived) {
              setTbldata(onDataReceived(data));
            } else {
              setTbldata(data.results);
            }
            setTotalPage(Number(data.count));
          }
        })
        .catch((error) => {
          errorToast("Something went wrong, please try again after sometime");
        })
        .finally((a) => {
          setLoading(false);
        });
    }
  }, [currentPage, formType, postData, url, searchValue, pageSize]);
  const handlePagination = (page) => {
    setCurrentPage(page);
  };
  const handlePerRowsChange = async (newPerPage) => {
    setPageSize(newPerPage);
  };
  const handleFilter = (e) => {
    const value = e.target.value;
    setSearchValue(value);
  };
  const handleEnterSearch = (e) => {
    const { value } = e.target;
    if (e.charCode === 13) {
      setSearchValue(value);
    }
  };
  // ** Custom Pagination , setTotalPage
  // const CustomPagination = () => {
  //   console.log(totalPage);
  //   return (
  //     <ReactPaginate
  //       previousLabel=""
  //       nextLabel=""
  //       forcePage={currentPage}
  //       onPageChange={(page) => handlePagination(page)}
  //       pageCount={totalPage / 10 || 1}
  //       breakLabel="..."
  //       pageRangeDisplayed={2}
  //       marginPagesDisplayed={2}
  //       activeClassName="active"
  //       pageClassName="page-item"
  //       breakClassName="page-item"
  //       breakLinkClassName="page-link"
  //       nextLinkClassName="page-link"
  //       nextClassName="page-item next"
  //       previousClassName="page-item prev"
  //       previousLinkClassName="page-link"
  //       pageLinkClassName="page-link"
  //       containerClassName="pagination react-paginate separated-pagination pagination-sm justify-content-end pr-1 mt-1"
  //     />
  //   );
  // };

  const getDataSets = () => {
    let cols = columns.filter((f) => !f.hideInExcel);
    let ds = [
      {
        rows: Tbldata || [],
        columns: cols,
        sheetName: sheetName,
      },
    ];
    return ds;
  };

  return (
    <div>
      {(!hideSearch || showDownload) && (
        <Row className="justify-content-end mx-0">
          {filterRenderor && filterRenderor()}
          <Col md="4" sm="12" className="d-flex align-items-center justify-content-end">
            {Tbldata && Tbldata.length > 0 && showDownload && (
              <>
                {downloadExcel && (
                  <Suspense fallback={<Spinner />}>
                    <ExcelDownload fileName={fileName} dataSets={getDataSets()} />
                  </Suspense>
                )}
                <PrimaryButton
                  text={"Download Excel"}
                  className=""
                  onClick={() => {
                    setdowloadExcel(true);
                    setTimeout(() => {
                      setdowloadExcel(false);
                    }, 1000);
                  }}
                />
              </>
            )}
            {!hideSearch && (
              <InputGroup className="input-group-merge mb-2">
                <InputGroupAddon addonType="prepend">
                  <InputGroupText>
                    <Search size={16} />
                  </InputGroupText>
                </InputGroupAddon>
                <Input
                  placeholder="search..."
                  value={searchValue}
                  onChange={(e) => handleFilter(e)}
                  onKeyPress={(e) => {
                    handleEnterSearch(e);
                  }}
                />
              </InputGroup>
            )}
            {/* <Button.Ripple color="primary" type="button" onClick={(e) => onRefresh()} className="mr-2">
              Refresh
            </Button.Ripple> */}
          </Col>
        </Row>
      )}
      <DataTable
        noHeader
        responsive
        selectableRows={false}
        columns={columns}
        className="react-dataTable"
        sortIcon={<ChevronDown size={10} />}
        data={Tbldata}
        pagination
        paginationTotalRows={totalPage || 1}
        progressPending={loading}
        progressComponent={<Spinner className={"m-2"} />}
        paginationServer={!!url}
        persistTableHead
        paginationRowsPerPageOptions={[5, 10, 25, 50, 75]}
        onChangeRowsPerPage={handlePerRowsChange}
        paginationPerPage={pageSize}
        onChangePage={handlePagination}
      />
    </div>
  );
};

export default TableComponent;
